import{G as a,c as t,b as o,ae as r}from"./chunks/framework.Cpb2nuHT.js";const c=JSON.parse('{"title":"AES加密解密出现：缺省的iv长度不能小于16","description":"","frontmatter":{"title":"AES加密解密出现：缺省的iv长度不能小于16","date":"2025/5/16","author":"花木凋零成兰","tags":["Java","AES加密"],"cover":false,"hiddenCover":true},"headers":[],"relativePath":"后端开发问题/AES加密解密出现：缺省的iv长度不能小于16.md","filePath":"后端开发问题/AES加密解密出现：缺省的iv长度不能小于16.md","lastUpdated":1747382752000}'),s={name:"后端开发问题/AES加密解密出现：缺省的iv长度不能小于16.md"};function n(l,e,i,d,_,h){return o(),t("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1747353600000"},[...e[0]||(e[0]=[r('<h1 id="aes加密解密出现-wrong-iv-length-must-be-16-bytes-long" tabindex="-1">AES加密解密出现：Wrong IV length: must be 16 bytes long <a class="header-anchor" href="#aes加密解密出现-wrong-iv-length-must-be-16-bytes-long" aria-label="Permalink to &quot;AES加密解密出现：Wrong IV length: must be 16 bytes long&quot;">​</a></h1><h2 id="原因描述" tabindex="-1">原因描述 <a class="header-anchor" href="#原因描述" aria-label="Permalink to &quot;原因描述&quot;">​</a></h2><p>当使用AES算法对数据进行加密时, 指定的加密 key 比较随意, 导致加密失败, 出现 <em>Wrong IV length: must be 16 bytes long</em> 的报错信息.</p><h2 id="问题解决" tabindex="-1">问题解决 <a class="header-anchor" href="#问题解决" aria-label="Permalink to &quot;问题解决&quot;">​</a></h2><p>即将加密的 key 修改为16位长度即可, 比如原加密key为 <code>key = &quot;ssss&quot;</code>, 补上其他字符到16位即可, 如: <code>key = &quot;ssssaaaabbbb&quot;</code>.</p><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><ul><li><a href="https://blog.csdn.net/wh445306/article/details/126383155" target="_blank" rel="noreferrer">JAVA 解密M3U8 视频TS片断提示：Wrong IV length: must be 16 bytes long 解决方法</a></li></ul>',7)])])}const u=a(s,[["render",n]]);export{c as __pageData,u as default};
